44	const groupItemsByType = (items: Item[]): Record<string, Item[]> => {
45	  const groups: Record<string, Item[]> = {};
46	  for (const item of items) {
47	    if (!groups[item.type]) {
48	      groups[item.type] = [];
49	    }
50	    groups[item.type].push(item);
51	  }
52	  return groups;
53	};
