55	const calculateSingleItemPremium = (item: Item): number => {
56	  const basePremium = BASE_PREMIUMS[item.type];
57	  const cursedSurcharge = item.cursed ? basePremium * CURSED_SURCHARGE_RATE : 0;
58	  const enchantmentSurcharge =
59	    item.enchantment !== undefined && item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD
60	      ? basePremium * HIGH_ENCHANTMENT_SURCHARGE_RATE
61	      : 0;
62	  return basePremium + cursedSurcharge + enchantmentSurcharge;
63	};
64	
65	const calculateGroupPremium = (typeItems: Item[]): number => {
66	  if (typeItems.length === BUILDING_BLOCK_SIZE) {
67	    return BUILDING_BLOCK_PREMIUM;
68	  }
69	  return typeItems.reduce((sum, item) => sum + calculateSingleItemPremium(item), 0);
70	};
