77	const calculateStepPremium = (
78	  step: Step,
79	  customerYears: number,
80	  isFollowUp: boolean,
81	): number => {
82	  const itemsPremium = calculateItemsPremium(step.items);
83	  const surcharge = itemsPremium * FIRST_INSURANCE_SURCHARGE_RATE;
84	  const loyaltyDiscount =
85	    customerYears >= LOYALTY_YEARS_THRESHOLD
86	      ? itemsPremium * LOYALTY_DISCOUNT_RATE
87	      : 0;
88	  const followUpDiscount = isFollowUp ? itemsPremium * FOLLOW_UP_DISCOUNT_RATE : 0;
89	  return Math.ceil(itemsPremium + surcharge - loyaltyDiscount - followUpDiscount + PROCESSING_FEE);
90	};
