92	export function processScenario(scenario: Scenario): ScenarioOutput {
93	  const results = scenario.steps.map((step, index) => {
94	    const premium = calculateStepPremium(step, scenario.customer.years, index > 0);
95	    return { premium };
96	  });
97	  return { results };
